#!/usr/bin/env python3
"""Tests for the CI workflow generator.

Run with::

    uv run python -m unittest discover -s .github/ci -t .github/ci -p 'test_*.py' -v

These tests are dependency-free (standard library only). They cover manifest
validation, behavior preservation, render idempotency, and the sync guarantee
between the checked-in workflow and the manifest.
"""

from __future__ import annotations

import tempfile
import unittest
from pathlib import Path
from typing import Any

import generate

ALL_VARIANTS = [
    "linux-arm64-egl",
    "linux-arm64-vulkan",
    "linux-x64-egl",
    "linux-x64-vulkan",
    "macos-arm64-metal",
    "macos-arm64-vulkan",
    "macos-arm64-egl",
    "ios-arm64-metal",
    "ios-simulator-arm64-metal",
    "windows-x64-vulkan",
    "windows-x64-wgl",
]


def _load() -> tuple[dict[str, Any], dict[str, dict[str, Any]]]:
    manifest = generate.load_manifest()
    steps = {s["name"]: s for s in manifest["step"]}
    return manifest, steps


def _variant(manifest: dict[str, Any], mise_env: str) -> dict[str, Any]:
    for entry in manifest["variant"]:
        if entry["mise_env"] == mise_env:
            return entry
    raise KeyError(mise_env)


class ManifestShapeTests(unittest.TestCase):
    def test_manifest_has_steps_and_variants(self) -> None:
        manifest = generate.load_manifest()
        self.assertIn("step", manifest)
        self.assertIn("variant", manifest)
        self.assertGreater(len(manifest["step"]), 0)
        self.assertGreater(len(manifest["variant"]), 0)

    def test_step_catalog_is_complete(self) -> None:
        for field in ("name", "label", "run"):
            for step in generate.load_manifest()["step"]:
                self.assertIn(field, step, f"step {step.get('name')!r} missing {field!r}")

    def test_step_names_are_unique(self) -> None:
        names = [s["name"] for s in generate.load_manifest()["step"]]
        self.assertEqual(len(names), len(set(names)))

    def test_variant_envs_match_expected_targets(self) -> None:
        envs = [v["mise_env"] for v in generate.load_manifest()["variant"]]
        self.assertEqual(envs, ALL_VARIANTS)

    def test_variant_envs_are_unique(self) -> None:
        envs = [v["mise_env"] for v in generate.load_manifest()["variant"]]
        self.assertEqual(len(envs), len(set(envs)))

    def test_every_variant_step_is_in_catalog(self) -> None:
        manifest = generate.load_manifest()
        catalog = {s["name"] for s in manifest["step"]}
        for variant in manifest["variant"]:
            for name in variant["steps"]:
                self.assertIn(name, catalog, f"{variant['mise_env']} references unknown {name}")

    def test_every_variant_has_a_build_manifest(self) -> None:
        for variant in generate.load_manifest()["variant"]:
            env = variant["mise_env"]
            self.assertTrue(
                (generate.MISE_CONFIG_DIR / f"config.{env}.toml").is_file(),
                f"no .mise/config.{env}.toml for CI variant {env}",
            )

    def test_every_variant_runs_exactly_one_native_pipeline(self) -> None:
        for variant in generate.load_manifest()["variant"]:
            steps = set(variant["steps"])
            self.assertEqual(
                steps & {"build_native", "test_native"},
                {"build_native"} if "build_native" in steps else {"test_native"},
                f"{variant['mise_env']} must run exactly one of build_native/test_native",
            )


class TargetSupportTests(unittest.TestCase):
    """Pin the per-variant policy so accidental manifest edits are caught."""

    def setUp(self) -> None:
        self.manifest, _ = _load()

    def _steps(self, mise_env: str) -> set[str]:
        return set(_variant(self.manifest, mise_env)["steps"])

    def test_ios_variants_are_build_only(self) -> None:
        for env in ("ios-arm64-metal", "ios-simulator-arm64-metal"):
            self.assertEqual(self._steps(env), {"build_native"})

    def test_macos_egl_runs_only_zig_and_native_test(self) -> None:
        self.assertEqual(
            self._steps("macos-arm64-egl"),
            {"test_native", "zig_binding", "zig_readback"},
        )

    def test_swift_example_runs_only_on_macos_metal(self) -> None:
        owners = [
            v["mise_env"]
            for v in self.manifest["variant"]
            if "swift_example" in v["steps"]
        ]
        self.assertEqual(owners, ["macos-arm64-metal"])

    def test_lwjgl_runs_exactly_on_vulkan_targets(self) -> None:
        owners = {
            v["mise_env"] for v in self.manifest["variant"] if "lwjgl" in v["steps"]
        }
        self.assertEqual(
            owners,
            {
                "linux-arm64-vulkan",
                "linux-x64-vulkan",
                "macos-arm64-vulkan",
                "windows-x64-vulkan",
            },
        )

    def test_swift_binding_runs_only_on_macos_metal_and_vulkan(self) -> None:
        owners = {
            v["mise_env"]
            for v in self.manifest["variant"]
            if "swift_binding" in v["steps"]
        }
        self.assertEqual(owners, {"macos-arm64-metal", "macos-arm64-vulkan"})

    def test_kotlin_native_excludes_arm64_windows_and_edge_targets(self) -> None:
        owners = {
            v["mise_env"]
            for v in self.manifest["variant"]
            if "kotlin_native" in v["steps"]
        }
        self.assertEqual(
            owners,
            {"linux-x64-egl", "linux-x64-vulkan", "macos-arm64-metal", "macos-arm64-vulkan"},
        )

    def test_desktop_binding_set_is_consistent(self) -> None:
        desktop = {
            "java_ffm",
            "java_jni",
            "dotnet",
            "rust_binding",
            "zig_binding",
            "rust_example",
            "zig_example",
        }
        for env in (
            "linux-arm64-egl",
            "linux-x64-egl",
            "linux-x64-vulkan",
            "macos-arm64-metal",
            "macos-arm64-vulkan",
            "windows-x64-vulkan",
            "windows-x64-wgl",
        ):
            steps = self._steps(env)
            self.assertTrue(
                desktop <= steps,
                f"{env} is missing desktop bindings: {desktop - steps}",
            )

    def test_arm64_vulkan_inherits_arm64_egl_plus_lwjgl(self) -> None:
        egl = self._steps("linux-arm64-egl")
        vulkan = self._steps("linux-arm64-vulkan")
        self.assertEqual(vulkan - egl, {"lwjgl"})


class RenderTests(unittest.TestCase):
    def test_render_is_idempotent(self) -> None:
        manifest = generate.load_manifest()
        self.assertEqual(generate.render(manifest), generate.render(manifest))

    def test_generate_is_idempotent(self) -> None:
        self.assertEqual(generate.generate(), generate.generate())

    def test_matrix_has_one_entry_per_variant(self) -> None:
        text = generate.generate()
        for env in ALL_VARIANTS:
            self.assertIn(f"- mise_env: {env}", text)

    def test_every_step_gated_by_contains_matrix_steps(self) -> None:
        manifest = generate.load_manifest()
        text = generate.generate()
        for step in manifest["step"]:
            self.assertIn(f"contains(matrix.steps, '{step['name']}')", text)

    def test_render_omits_handwritten_env_prefix_conditions(self) -> None:
        text = generate.generate()
        for fragment in ("startsWith(matrix.mise_env", "matrix.mise_env != '"):
            self.assertNotIn(fragment, text)

    def test_generated_workflow_matches_checked_in(self) -> None:
        current = generate.WORKFLOW_PATH.read_text()
        self.assertEqual(
            generate.generate(),
            current,
            (
                ".github/workflows/ci.yml is out of sync with "
                ".github/ci/manifest.toml.\n"
                "Run `mise run ci:generate` and commit the result."
            ),
        )


class ValidationFailureTests(unittest.TestCase):
    """Validation must fail loudly on the drift modes that hand-editing allows."""

    def _base_manifest(self) -> dict[str, Any]:
        return {
            "step": [
                {"name": "build_native", "label": "Build", "run": "mise run build"},
                {"name": "test_native", "label": "Test", "run": "mise run test"},
            ],
            "variant": [
                {
                    "mise_env": "linux-x64-egl",
                    "runner": "ubuntu-latest",
                    "steps": ["test_native"],
                }
            ],
        }

    def test_rejects_unknown_step(self) -> None:
        manifest = self._base_manifest()
        manifest["variant"][0]["steps"] = ["test_native", "no_such_step"]
        with self.assertRaisesRegex(ValueError, "unknown step"):
            generate.validate(manifest)

    def test_rejects_duplicate_step_name(self) -> None:
        manifest = self._base_manifest()
        manifest["step"].append(
            {"name": "test_native", "label": "Dup", "run": "mise run test"}
        )
        with self.assertRaisesRegex(ValueError, "duplicate step name"):
            generate.validate(manifest)

    def test_rejects_duplicate_variant_env(self) -> None:
        manifest = self._base_manifest()
        manifest["variant"].append(dict(manifest["variant"][0]))
        with self.assertRaisesRegex(ValueError, "duplicate variant mise_env"):
            generate.validate(manifest)

    def test_rejects_both_build_and_test(self) -> None:
        manifest = self._base_manifest()
        manifest["variant"][0]["steps"] = ["build_native", "test_native"]
        with self.assertRaisesRegex(ValueError, "both build_native and test_native"):
            generate.validate(manifest)

    def test_rejects_neither_build_nor_test(self) -> None:
        manifest = self._base_manifest()
        manifest["variant"][0]["steps"] = []
        with self.assertRaisesRegex(ValueError, "must list build_native or test_native"):
            generate.validate(manifest)

    def test_rejects_variant_without_build_manifest(self) -> None:
        manifest = self._base_manifest()
        manifest["variant"][0]["mise_env"] = "made-up-env"
        manifest["variant"][0]["steps"] = ["test_native"]
        with tempfile.TemporaryDirectory() as tmp:
            with unittest.mock.patch.object(generate, "MISE_CONFIG_DIR", Path(tmp)):
                with self.assertRaisesRegex(ValueError, "no build manifest"):
                    generate.validate(manifest)


if __name__ == "__main__":
    import unittest.mock  # noqa: E402

    unittest.main()
else:
    import unittest.mock  # noqa: E402

